class CodeCommit:
    """Represents a commit in the code repository."""

    def __init__(self, author_id, message, files_changed, branch='main'):
        self.id = str(uuid.uuid4())
        self.hash = hashlib.sha1(
            f"{author_id}{message}{datetime.now().isoformat()}".encode()
        ).hexdigest()[:8]
        self.author_id = author_id
        self.message = message
        self.files_changed = files_changed
        self.branch = branch
        self.timestamp = datetime.now()

    def to_dict(self):
        return {
            'id': self.id,
            'hash': self.hash,
            'author_id': self.author_id,
            'message': self.message,
            'files_changed': self.files_changed,
            'branch': self.branch,
            'timestamp': self.timestamp.isoformat(),
        }


class CodeRepository:
    """Represents a code repository for a project."""

    def __init__(self, project_id):
        self.id = str(uuid.uuid4())
        self.project_id = project_id
        self.branches = ['main']
        self.commits = defaultdict(list)
        self.files = defaultdict(dict)
        self.created_at = datetime.now()

    def create_branch(self, branch_name, from_branch='main'):
        if branch_name in self.branches:
            raise ValueError(f"Branch '{branch_name}' already exists.")
        if from_branch not in self.branches:
            raise ValueError(f"Source branch '{from_branch}' does not exist.")
        self.branches.append(branch_name)
        self.files[branch_name] = dict(self.files[from_branch])
        return branch_name

    def delete_branch(self, branch_name):
        if branch_name == 'main':
            raise ValueError("Cannot delete the main branch.")
        if branch_name not in self.branches:
            raise ValueError(f"Branch '{branch_name}' does not exist.")
        self.branches.remove(branch_name)
        self.files.pop(branch_name, None)
        self.commits.pop(branch_name, None)

    def commit(self, author_id, message, files_changed, branch='main'):
        if branch not in self.branches:
            raise ValueError(f"Branch '{branch}' does not exist.")
        commit = CodeCommit(author_id, message, files_changed, branch)
        self.commits[branch].append(commit)
        for file_path, content in files_changed.items():
            if content is None:
                self.files[branch].pop(file_path, None)
            else:
                self.files[branch][file_path] = content
        return commit

    def get_file(self, file_path, branch='main'):
        if branch not in self.branches:
            raise ValueError(f"Branch '{branch}' does not exist.")
        return self.files[branch].get(file_path)

    def get_commit_history(self, branch='main', limit=50):
        if branch not in self.branches:
            raise ValueError(f"Branch '{branch}' does not exist.")
        return self.commits[branch][-limit:]

    def merge_branch(self, source_branch, target_branch='main'):
        if source_branch not in self.branches:
            raise ValueError(f"Source branch '{source_branch}' does not exist.")
        if target_branch not in self.branches:
            raise ValueError(f"Target branch '{target_branch}' does not exist.")
        source_files = self.files[source_branch]
        for file_path, content in source_files.items():
            self.files[target_branch][file_path] = content
        merge_commit = CodeCommit(
            'system', f"Merge branch '{source_branch}' into '{target_branch}'",
            source_files, target_branch
        )
        self.commits[target_branch].append(merge_commit)
        return merge_commit


