class UserService:
    """Service for managing user operations."""

    def __init__(self):
        self.users = {}
        self.usernames = set()
        self.emails = set()

    def create_user(self, username, email, password, display_name=""):
        errors = self._validate_user_creation(username, email, password)
        if errors:
            raise ValueError("; ".join(errors))

        user = User(username, email, password, display_name)
        self.users[user.id] = user
        self.usernames.add(username.lower())
        self.emails.add(email.lower())
        return user

    def _validate_user_creation(self, username, email, password):
        errors = []
        if not username or not username.strip():
            errors.append("Username is required")
        elif len(username) > User.MAX_NAME_LENGTH:
            errors.append(f"Username exceeds {User.MAX_NAME_LENGTH} characters")
        elif username.lower() in self.usernames:
            errors.append("Username already taken")

        if not email or not email.strip():
            errors.append("Email is required")
        elif not User.EMAIL_REGEX.match(email):
            errors.append("Invalid email format")
        elif email.lower() in self.emails:
            errors.append("Email already registered")

        if not password:
            errors.append("Password is required")
        elif len(password) < 6:
            errors.append("Password must be at least 6 characters")

        return errors

    def get_user(self, user_id):
        return self.users.get(user_id)

    def get_user_by_username(self, username):
        for user in self.users.values():
            if user.username.lower() == username.lower():
                return user
        return None

    def update_user(self, user_id, **kwargs):
        user = self.users.get(user_id)
        if not user:
            raise ValueError("User not found")
        if 'bio' in kwargs and len(kwargs['bio']) > User.MAX_BIO_LENGTH:
            raise ValueError(f"Bio exceeds {User.MAX_BIO_LENGTH} characters")
        user.update_profile(**kwargs)
        return user

    def deactivate_user(self, user_id):
        user = self.users.get(user_id)
        if user:
            user.is_active = False
            return True
        return False

    def get_all_users(self):
        return list(self.users.values())


class ProjectService:
    """Service for managing project operations."""

    def __init__(self):
        self.projects = {}

    def create_project(self, title, description, owner_id, required_skills=None):
        errors = self._validate_project_creation(title, description)
        if errors:
            raise ValueError("; ".join(errors))

        project = Project(title, description, owner_id, required_skills)
        self.projects[project.id] = project
        return project

    def _validate_project_creation(self, title, description):
        errors = []
        if not title or not title.strip():
            errors.append("Project title is required")
        elif len(title) > Project.MAX_TITLE_LENGTH:
            errors.append(f"Title exceeds {Project.MAX_TITLE_LENGTH} characters")

        if not description or not description.strip():
            errors.append("Project description is required")
        elif len(description) > Project.MAX_DESCRIPTION_LENGTH:
            errors.append(f"Description exceeds {Project.MAX_DESCRIPTION_LENGTH} characters")

        return errors

    def get_project(self, project_id):
        return self.projects.get(project_id)

    def get_projects_by_owner(self, owner_id):
        return [p for p in self.projects.values() if p.owner_id == owner_id]

    def get_projects_by_member(self, user_id):
        return [p for p in self.projects.values() if user_id in p.members]

    def update_project(self, project_id, **kwargs):
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        for key, value in kwargs.items():
            if hasattr(project, key) and key not in ('id', 'owner_id', 'created_at'):
                setattr(project, key, value)
        project.updated_at = datetime.now()
        return project

    def delete_project(self, project_id):
        if project_id in self.projects:
            del self.projects[project_id]
            return True
        return False

    def get_all_projects(self):
        return list(self.projects.values())


class SearchService:
    """Service for searching and matching users and projects."""

    def __init__(self, user_service, project_service):
        self.user_service = user_service
        self.project_service = project_service

    def search_users(self, query=None, skills=None, interests=None):
        results = self.user_service.get_all_users()
        results = [u for u in results if u.is_active]

        if query:
            query_lower = query.lower()
            results = [
                u for u in results
                if query_lower in u.username.lower()
                or query_lower in u.display_name.lower()
                or query_lower in u.bio.lower()
            ]

        if skills:
            skills_lower = [s.lower() for s in skills]
            results = [
                u for u in results
                if any(s in u.skills for s in skills_lower)
            ]

        if interests:
            interests_lower = [i.lower() for i in interests]
            results = [
                u for u in results
                if any(i in u.interests for i in interests_lower)
            ]

        return results

    def search_projects(self, query=None, skills=None, status=None, tags=None):
        results = self.project_service.get_all_projects()

        if query:
            query_lower = query.lower()
            results = [
                p for p in results
                if query_lower in p.title.lower()
                or query_lower in p.description.lower()
            ]

        if skills:
            skills_lower = [s.lower() for s in skills]
            results = [
                p for p in results
                if any(s in [rs.lower() for rs in p.required_skills] for s in skills_lower)
            ]

        if status:
            results = [p for p in results if p.status == status]

        if tags:
            tags_lower = [t.lower() for t in tags]
            results = [
                p for p in results
                if any(t in [pt.lower() for pt in p.tags] for t in tags_lower)
            ]

        return results

    def match_projects_for_user(self, user_id):
        """Match projects based on user skills and interests."""
        user = self.user_service.get_user(user_id)
        if not user:
            return []

        projects = self.project_service.get_all_projects()
        scored_projects = []

        for project in projects:
            if user_id in project.members:
                continue
            if project.status in ('completed', 'archived'):
                continue

            score = self._calculate_match_score(user, project)
            if score > 0:
                scored_projects.append((project, score))

        scored_projects.sort(key=lambda x: x[1], reverse=True)
        return scored_projects

    def match_users_for_project(self, project_id):
        """Match users based on project requirements."""
        project = self.project_service.get_project(project_id)
        if not project:
            return []

        users = self.user_service.get_all_users()
        scored_users = []

        for user in users:
            if not user.is_active:
                continue
            if user.id in project.members:
                continue

            score = self._calculate_match_score(user, project)
            if score > 0:
                scored_users.append((user, score))

        scored_users.sort(key=lambda x: x[1], reverse=True)
        return scored_users

    def _calculate_match_score(self, user, project):
        """Calculate compatibility score between a user and a project."""
        score = 0.0

        # Skill matching (weighted higher)
        if project.required_skills and user.skills:
            required_lower = [s.lower() for s in project.required_skills]
            user_skills_lower = [s.lower() for s in user.skills]
            matching_skills = set(required_lower) & set(user_skills_lower)
            if required_lower:
                score += (len(matching_skills) / len(required_lower)) * 60

        # Interest matching
        if project.tags and user.interests:
            tags_lower = [t.lower() for t in project.tags]
            interests_lower = [i.lower() for i in user.interests]
            matching_interests = set(tags_lower) & set(interests_lower)
            if tags_lower:
                score += (len(matching_interests) / len(tags_lower)) * 30

        # Activity bonus (projects with fewer members get a slight boost)
        if len(project.members) < project.max_members:
            openness_ratio = 1 - (len(project.members) / project.max_members)
            score += openness_ratio * 10

        return round(score, 2)


class MessagingService:
    """Service for managing messaging and channels."""

    def __init__(self):
        self.channels = {}

    def create_channel(self, name, project_id, channel_type='general'):
        channel = Channel(name, project_id, channel_type)
        self.channels[channel.id] = channel
        return channel

    def get_channel(self, channel_id):
        return self.channels.get(channel_id)

    def get_channels_for_project(self, project_id):
        return [c for c in self.channels.values() if c.project_id == project_id]

    def send_message(self, sender_id, channel_id, content):
        channel = self.channels.get(channel_id)
        if not channel:
            raise ValueError("Channel not found")
        if not content or not content.strip():
            raise ValueError("Message content cannot be empty")
        if len(content) > Message.MAX_CONTENT_LENGTH:
            raise ValueError(f"Message exceeds {Message.MAX_CONTENT_LENGTH} characters")
        if sender_id not in channel.members:
            raise ValueError("User is not a member of this channel")

        message = Message(sender_id, content, channel_id)
        channel.add_message(message)
        return message

    def get_messages(self, channel_id, limit=50, offset=0):
        channel = self.channels.get(channel_id)
        if not channel:
            raise ValueError("Channel not found")
        return channel.get_messages(limit, offset)

    def edit_message(self, message_id, channel_id, new_content):
        channel = self.channels.get(channel_id)
        if not channel:
            raise ValueError("Channel not found")
        for msg in channel.messages:
            if msg.id == message_id:
                msg.edit(new_content)
                return msg
        raise ValueError("Message not found")

    def delete_channel(self, channel_id):
        if channel_id in self.channels:
            del self.channels[channel_id]
            return True
        return False


