class CollaborateCraft:
    """Main application class that ties all services together."""

    def __init__(self):
        self.user_service = UserService()
        self.project_service = ProjectService()
        self.search_service = SearchService(self.user_service, self.project_service)
        self.messaging_service = MessagingService()
        self.collaboration_service = CollaborationService()

    # User operations
    def register_user(self, username, email, password, display_name=""):
        return self.user_service.create_user(username, email, password, display_name)

    def get_user(self, user_id):
        return self.user_service.get_user(user_id)

    def update_user_profile(self, user_id, **kwargs):
        return self.user_service.update_user(user_id, **kwargs)

    # Project operations
    def create_project(self, title, description, owner_id, required_skills=None):
        project = self.project_service.create_project(
            title, description, owner_id, required_skills
        )
        self.collaboration_service.create_repository(project.id)
        board = self.collaboration_service.create_task_board(project.id)
        channel = self.messaging_service.create_channel('general', project.id)
        channel.add_member(owner_id)
        return project

    def join_project(self, project_id, user_id):
        project = self.project_service.get_project(project_id)
        if not project:
            raise ValueError("Project not found")
        project.add_member(user_id)
        channels = self.messaging_service.get_channels_for_project(project_id)
        for ch in channels:
            ch.add_member(user_id)
        return project

    def leave_project(self, project_id, user_id):
        project = self.project_service.get_project(project_id)
        if not project:
            raise ValueError("Project not found")
        project.remove_member(user_id)
        channels = self.messaging_service.get_channels_for_project(project_id)
        for ch in channels:
            ch.remove_member(user_id)
        return project

    # Search operations
    def search_users(self, **kwargs):
        return self.search_service.search_users(**kwargs)

    def search_projects(self, **kwargs):
        return self.search_service.search_projects(**kwargs)

    def get_project_matches(self, user_id):
        return self.search_service.match_projects_for_user(user_id)

    def get_user_matches(self, project_id):
        return self.search_service.match_users_for_project(project_id)

    # Messaging operations
    def send_message(self, sender_id, channel_id, content):
        return self.messaging_service.send_message(sender_id, channel_id, content)

    def get_messages(self, channel_id, limit=50, offset=0):
        return self.messaging_service.get_messages(channel_id, limit, offset)

    # Repository operations
    def commit_code(self, project_id, author_id, message, files_changed, branch='main'):
        repo = self.collaboration_service.get_repository(project_id)
        if not repo:
            raise ValueError("Repository not found")
        return repo.commit(author_id, message, files_changed, branch)

    def create_branch(self, project_id, branch_name, from_branch='main'):
        repo = self.collaboration_service.get_repository(project_id)
        if not repo:
            raise ValueError("Repository not found")
        return repo.create_branch(branch_name, from_branch)

    # Task board operations
    def create_task(self, project_id, title, description, assignee_id=None, priority='medium'):
        board = self.collaboration_service.get_task_board(project_id)
        if not board:
            raise ValueError("Task board not found")
        return board.create_task(title, description, assignee_id, priority)

    def get_tasks(self, project_id, status=None, assignee_id=None):
        board = self.collaboration_service.get_task_board(project_id)
        if not board:
            raise ValueError("Task board not found")
        if status:
            return board.get_tasks_by_status(status)
        if assignee_id:
            return board.get_tasks_by_assignee(assignee_id)
        return board.tasks


