    def test_full_collaboration_workflow(self):
        app = CollaborateCraft()

        # Register users
        alice = app.register_user("alice", "alice@example.com", "password123")
        alice.add_skill("python")
        alice.add_skill("fastapi")
        alice.add_interest("web development")

        bob = app.register_user("bob", "bob@example.com", "password123")
        bob.add_skill("javascript")
        bob.add_skill("react")
        bob.add_interest("web development")

        # Create project
        project = app.create_project(
            "Web Dashboard", "Real-time analytics dashboard",
            alice.id, ["python", "javascript", "react"]
        )
        project.tags = ["web development", "analytics"]

        # Bob finds and joins the project
        matches = app.get_project_matches(bob.id)
        self.assertTrue(len(matches) > 0)
        app.join_project(project.id, bob.id)

        # Team communicates
        channels = app.messaging_service.get_channels_for_project(project.id)
        channel = channels[0]
        app.send_message(alice.id, channel.id, "Welcome to the project!")
        app.send_message(bob.id, channel.id, "Excited to contribute!")
        messages = app.get_messages(channel.id)
        self.assertEqual(len(messages), 2)

        # Work on code
        app.commit_code(
            project.id, alice.id, "Set up project structure",
            {"app.py": "from fastapi import FastAPI\napp = FastAPI()"}
        )
        app.create_branch(project.id, "feature/frontend")
        app.commit_code(
            project.id, bob.id, "Add React frontend",
            {"src/App.jsx": "export default function App() { return <div/>; }"},
            branch="feature/frontend"
        )

        # Merge feature branch
        repo = app.collaboration_service.get_repository(project.id)
        repo.merge_branch("feature/frontend", "main")
        self.assertIsNotNone(repo.get_file("src/App.jsx", "main"))

        # Task management
        task1 = app.create_task(
            project.id, "Add authentication", "Implement JWT auth",
            alice.id, "high"
        )
        task2 = app.create_task(
            project.id, "Build charts component", "Create dashboard charts",
            bob.id, "medium"
        )
        task1.set_status("in_progress")
        task2.set_status("in_progress")
        task2.set_status("done")

        # Verify final state
        done_tasks = app.get_tasks(project.id, status="done")
        self.assertEqual(len(done_tasks), 1)
        self.assertEqual(done_tasks[0].title, "Build charts component")

